module alu(
    input [31:0] a, b,
    input [5:0] aluc,
    output [31:0] r,
    output zero, carry, negative, overflow, flag
);
    parameter ADD = 6'b100000;
    parameter ADDU = 6'b100001;
    parameter SUB = 6'b100010;
    parameter SUBU = 6'b100011;
    parameter AND = 6'b100100;
    parameter OR = 6'b100101;
    parameter XOR = 6'b100110;
    parameter NOR = 6'b100111;
    parameter SLT = 6'b101010;
    parameter SLTU = 6'b101011;
    parameter SLL = 6'b000000;
    parameter SRL = 6'b000010;
    parameter SRA = 6'b000011;
    parameter SLLV = 6'b000100;
    parameter SRLV = 6'b000110;
    parameter SRAV = 6'b000111;
    parameter LUI = 6'b001111;
    wire [31:0] a_signed, b_signed;
    reg [31:0] res;
    reg [32:0] temp;
    reg flag_reg;
    assign a_signed = a;
    assign b_signed = b;
    assign r = res[31:0];
    assign zero = (res == 32'b0) ? 1'b1 : 1'b0;
    assign carry = (temp[33:32] != 2'b0) ? 1'b1 : 1'b0;
    assign negative = (res[31] == 1'b1) ? 1'b1 : 1'b0;
    assign overflow = (temp[31] != temp[32]) ? 1'b1 : 1'b0;
    assign flag = flag_reg;
    always @(*) begin
        case (aluc)
            ADD: begin
                temp = {a_signed[31], a_signed} + {b_signed[31], b_signed};
                res = temp[31:0];
                flag_reg = 1'bz;
            end
            ADDU: begin
                res = a + b;
                flag_reg = 1'bz;
            end
            SUB: begin
                temp = {a_signed[31], a_signed} - {b_signed[31], b_signed};
                res = temp[31:0];
                flag_reg = 1'bz;
            end
            SUBU: begin
                res = a - b;
                flag_reg = 1'bz;
            end
            AND: begin
                res = a & b;
                flag_reg = 1'bz;
            end
            OR: begin
                res = a | b;
                flag_reg = 1'bz;
            end
            XOR: begin
                res = a ^ b;
                flag_reg = 1'bz;
            end
            NOR: begin
                res = ~(a | b);
                flag_reg = 1'bz;
            end
            SLT: begin
                temp = {a_signed[31], a_signed} - {b_signed[31], b_signed};
                res = {31'b0, temp[31]};
                flag_reg = temp[32];
            end
            SLTU: begin
                res = (a < b) ? 32'b1 : 32'b0;
                flag_reg = (a < b) ? 1'b1 : 1'b0;
            end
            SLL: begin
                res = b << a[4:0];
                flag_reg = 1'bz;
            end
            SRL: begin
                res = b >> a[4:0];
                flag_reg = 1'bz;
            end
            SRA: begin
                res = b_signed >>> a[4:0];
                flag_reg = 1'bz;
            end
            SLLV: begin
                res = b << a[4:0];
                flag_reg = 1'bz;
            end
            SRLV: begin
                res = b >> a[4:0];
                flag_reg = 1'bz;
            end
            SRAV: begin
                res = b_signed >>> a[4:0];
                flag_reg = 1'bz;
            end
            LUI: begin
                res = {b[15:0], 16'b0};
                flag_reg = 1'bz;
            end
            default: begin
                res = 32'b0;
                flag_reg = 1'bz;
            end
    endcase
end // Auto-repaired
endmodule
